const d = $input.first().json;
const eventDate = d.eventDate || new Date(Date.now() + 60*24*60*60*1000).toISOString().split('T')[0];
const eventEndDate = d.eventEndDate || new Date(new Date(eventDate).getTime() + 4*24*60*60*1000).toISOString().split('T')[0];

return [{ json: {
  ...d,
  phase: 7,
  eventDate,
  eventEndDate,
  showLength: d.showLength || '4 days',
  retailerLocation: d.retailerLocation || 'TBD - Pending Store Selection',
  logisticsPlan: {
    inboundShipping: 'Scheduled',
    deliveryAppointment: 'Pending',
    bolPrepared: false,
    staffingConfirmed: false,
    powerDropConfirmed: false,
    preEventCallCompleted: false
  },
  staffingNeeds: '2 trained brand ambassadors per location',
  shippingDeadline: new Date(new Date(eventDate).getTime() - 7*24*60*60*1000).toISOString().split('T')[0],
  logisticsCreatedAt: new Date().toISOString()
} }];

